rubric.en:
Expected code/algorithm:
CHLPS(P) {
  n = P.size();
  if (P[0] != P[n-1]) {
    P[n] = P[0];
    n = n+1;
  }
  L[0] = P[0]; L[1] = P[1]; k = 2;
  for (i = 2; i < n; ++i) {
    while (k >= 2 && ccw(L[k-2], L[k-1], P[i]) < 0) {
      --k;
    }
    L[k] = P[i];
    ++k;
  }
  return L;
}

